import java.time.*;
import java.time.format.DateTimeFormatter;
import java.time.temporal.ChronoUnit;

public class DateTimeDemo {
    public static void main(String[] args) {
        // Current Date
        LocalDate today = LocalDate.now();
        System.out.println("Today: " + today);

        // Adding and Subtracting (Returns new object because it's immutable!)
        LocalDate nextWeek = today.plus(1, ChronoUnit.WEEKS);
        System.out.println("Next Week: " + nextWeek);

        // Formatting
        DateTimeFormatter formatter = DateTimeFormatter.ofPattern("dd MMM yyyy");
        System.out.println("Formatted: " + today.format(formatter));

        // Timezones
        ZonedDateTime tokyoTime = ZonedDateTime.now(ZoneId.of("Asia/Tokyo"));
        System.out.println("Tokyo Time: " + tokyoTime);

        // Calculating differences (Period for dates, Duration for time)
        LocalDate birthDate = LocalDate.of(1995, Month.MAY, 23);
        Period age = Period.between(birthDate, today);
        System.out.println("Age: " + age.getYears() + " years");
    }
}

